const MAPS={sa3010:{cols:['a3_cod','a3_nome','a3_nreduz'],types:['str','str','str']},cc2010:{cols:['cc2_est','cc2_codmun','cc2_mun'],types:['str','str','str']},za7010:{cols:['za7_data','za7_hora','za7_operad','za7_nomeop','za7_assunto','za7_contato','za7_cliente','za7_nome_cli','za7_vend','za7_compl'],types:['date','str','str','str','str','str','str','str','str','str']},sf2010:{cols:['f2_doc','f2_serie','f2_cliente','f2_loja','f2_emissao','f2_valor'],types:['str','str','str','str','date','num']},sc5010:{cols:['c5_num','c5_cliente','c5_loja','c5_nome','c5_vend','c5_emissao','c5_le_raw'],types:['str','str','str','str','str','date','str']},sa1010:{cols:['a1_codcli_raw','a1_nome','a1_nreduz','a1_pessoa','a1_cgc','a1_pricom','a1_ultcom','a1_vend','a1_risco','a1_lc','a1_sativ1','a1_end','a1_cep','a1_bairro','a1_est','a1_cod_mun','a1_mun','a1_ativo_raw','a1_inativo_raw'],types:['str','str','str','str','str','date','date','str','str','num','str','str','str','str','str','str','str','str','str']},sb1010:{cols:['b1_cod','b1_desc','b1_tipo','b1_um','b1_grupo','b1_prv1'],types:['str','str','str','str','str','num']},sbm010:{cols:['bm_grupo','bm_desc'],types:['str','str']},sd2010:{cols:['d2_item','d2_cod','d2_quant','d2_prcven','d2_total','d2_descon','d2_tes','d2_cf','d2_pedido','d2_cliente','d2_loja','d2_doc','d2_serie','d2_grupo','d2_emissao'],types:['str','str','num','num','num','num','str','str','str','str','str','str','str','str','date']},sf4010:{cols:['f4_codigo','f4_tipo','f4_cf','f4_texto'],types:['str','str','str','str']},sx5010:{cols:['x5_tabela','x5_chave','x5_descri'],types:['str','str','str']},sz1010:{cols:['z1_cod','z1_clicod','z1_loja','z1_statua','z1_statud','z1_riscoa','z1_riscod','z1_tpalt','z1_pedido','z1_usunom','z1_data','z1_hora'],types:['str','str','str','str','str','str','str','str','str','str','date','str']}};
const spec=MAPS[table];const n=spec.cols.length;
