const clientErr=body.error?String(body.error):null;
if(!ingestId)return[{json:{ok:false,error:'ingest_id obrigatório',sql:'SELECT 1'}}];
const refreshFns=table==='sf2010'?['castor_refresh_metrics_sf','castor_refresh_metrics_alltime']:table==='sc5010'?['castor_refresh_metrics_sc','castor_refresh_sc5_address','castor_refresh_metrics_alltime']:table==='sd2010'?['castor_refresh_metrics_sd2']:table==='sa1010'?['castor_refresh_sa1010_derived']:null;
const clientErrLit=clientErr?("'"+clientErr.replace(/'/g,"''")+"'"):'NULL';
const okLit=okFlag?'TRUE':'FALSE';
let sql;
if(refreshFns){
  // Bloco PL/pgSQL: tenta cada refresh em sequência; se qualquer falhar, captura SQLERRM
  // e SEMPRE chama log_finish marcando ok=false e gravando o primeiro erro.
  const performBlock=refreshFns.map(fn=>'    BEGIN PERFORM '+fn+'(); EXCEPTION WHEN OTHERS THEN IF v_refresh_err IS NULL THEN v_refresh_err := '+"'"+fn+': '+"'"+' || SQLERRM; END IF; END;').join('\n');
  sql='DO $f$\n'+
      'DECLARE v_refresh_err text := NULL;\n'+
      'BEGIN\n'+
      performBlock+'\n'+
      '  PERFORM castor_ingest_log_finish(\n'+
      "    '"+ingestId+"'::uuid,\n"+
      '    '+rowsIn+',\n'+
      '    CASE WHEN '+okLit+' AND v_refresh_err IS NULL THEN '+rowsIn+' ELSE 0 END,\n'+
      '    '+duration+',\n'+
      '    ('+okLit+' AND v_refresh_err IS NULL),\n'+
      '    COALESCE('+clientErrLit+', v_refresh_err)\n'+
      '  );\n'+
      'END $f$;';
}else{
  sql="SELECT castor_ingest_log_finish('"+ingestId+"'::uuid, "+rowsIn+", "+(okFlag?rowsIn:0)+", "+duration+", "+okLit+", "+clientErrLit+");";
}
return[{json:{ok:true,ingest_id:ingestId,table,rows_in:rowsIn,rows_out:okFlag?rowsIn:0,duration_ms:duration,err:clientErr,sql}}];
